from collections import deque
from heapq import heappush, heappop

# Model inferred from RELIQUARY.md and spot-checks against the executable.
open_base={(0,0),(1,0),(1,1),(1,2),(1,3),(1,4),(3,1),(3,2),(3,3)}
gate=(2,1)
dice_dirs=['N','E','S','W']
dir_delta={'N':(-1,0),'E':(0,1),'S':(1,0),'W':(0,-1)}
move_delta={'north':(-1,0),'south':(1,0),'east':(0,1),'west':(0,-1)}
cmds=['move east','move north','move south','move west','push amber east','take sun','turn alpha clockwise','turn alpha counterclockwise','use sun reliquary']
# lex order will be Python string order; use sorted for final tie-break enumeration.
cmds=sorted(cmds)

class S(tuple):
    __slots__=()

# state = (player, amber, alpha_idx, sun_carried, solved)
start=((1,0),(1,1),0,False,False)

def gate_open(s):
    return s[1]==(1,4)

def open_tiles(s):
    tiles=set(open_base)
    if gate_open(s):
        tiles.add(gate)
    return tiles

def turn_idx(i, cw):
    return (i+1)%4 if cw else (i-1)%4

def apply_conveyor(amber, alpha_idx):
    if amber==(1,1):
        dr,dc=dir_delta[dice_dirs[alpha_idx]]
        return (amber[0]+dr, amber[1]+dc)
    return amber

def legal_and_next(s, cmd):
    player, amber, alpha_idx, sun_carried, solved = s
    if solved:
        return None
    p=player; a=amber; ai=alpha_idx; sc=sun_carried
    irreversible_gain=0
    pushes_gain=0
    wear_gain=0
    # phase1 action
    if cmd.startswith('move '):
        d=cmd.split()[1]
        dr,dc=move_delta[d]
        np=(p[0]+dr,p[1]+dc)
        if np not in open_tiles(s) or np==a:
            return None
        p=np
    elif cmd=='push amber east':
        if p!=(a[0],a[1]-1):
            return None
        dest=(a[0],a[1]+1)
        if dest not in open_tiles(s) or dest==p:
            return None
        a=dest
        pushes_gain=1
    elif cmd=='turn alpha clockwise':
        # adjacent orthogonally to dial
        if abs(p[0]-0)+abs(p[1]-0)!=1:
            return None
        ai=turn_idx(ai, True)
    elif cmd=='turn alpha counterclockwise':
        if abs(p[0]-0)+abs(p[1]-0)!=1:
            return None
        ai=turn_idx(ai, False)
    elif cmd=='take sun':
        if p!=(3,1) or sc:
            return None
        sc=True
    elif cmd=='use sun reliquary':
        if p!=(3,3) or not sc or a!=(1,4) or dice_dirs[ai] != 'E':
            return None
        sc=False
        solved=True
        irreversible_gain += 1
    else:
        raise ValueError(cmd)

    # phase2 primary ice slide on requested push only
    if cmd=='push amber east' and a in {(1,2),(1,3)}:
        # slide east through consecutive ice tiles; wear for each ice tile entered during primary sliding
        # already entered current a which is ice
        while a in {(1,2),(1,3)}:
            wear_gain += 1
            nxt=(a[0],a[1]+1)
            a=nxt
    # phase3 conveyor movement
    prev_a=a
    a=apply_conveyor(a, ai)
    # conveyor can move crate anywhere one tile, even onto player? assume illegal states not reachable? let's validate; docs imply deterministic.
    # In practice from (1,1) with player at (1,0) only turn can move to (1,2); no conflict.

    # phase4 plate/gate and irreversibility
    if a==(1,4) and prev_a!=(1,4):
        irreversible_gain += 1

    return (p,a,ai,sc,solved), (1,pushes_gain,wear_gain,irreversible_gain), solved

# Dijkstra on lexicographic cost tuple with path tie-break by command list lexicographic order.
# We'll store best by state on full (cost_tuple, path)
heap=[]
heappush(heap, ((0,0,0,0), [], start))
best={start: ((0,0,0,0), [])}
solutions=[]
while heap:
    cost,path,s=heappop(heap)
    if best.get(s)!=(cost,path):
        continue
    if s[4]:
        solutions.append((cost,path,s))
        # because heap ordered by cost then path lexicographically, first solved is global optimum.
        break
    for cmd in cmds:
        res=legal_and_next(s,cmd)
        if not res:
            continue
        ns, delta, solved = res
        ncost=tuple(cost[i]+delta[i] for i in range(4))
        npath=path+[cmd]
        prev=best.get(ns)
        if prev is None or (ncost,npath) < prev:
            best[ns]=(ncost,npath)
            heappush(heap,(ncost,npath,ns))

print('best solution:', solutions[0][0], solutions[0][1])
print('states explored', len(best))
